      "rmdir -p tmp/build/cache  # remove cache, then build, then tmp if all empty",
      "rmdir --ignore-fail-on-non-empty dir  # don't error if it's not empty",
      "ls -A tmp-scratch  # check what's blocking rmdir (any output = blockers)"
