    outputExample: "$ sudo chattr +i /etc/nginx/nginx.conf\n$ sudo rm /etc/nginx/nginx.conf\nrm: cannot remove '/etc/nginx/nginx.conf': Operation not permitted\n$ lsattr /etc/nginx/nginx.conf\n----i--------e-- /etc/nginx/nginx.conf",
