      "make > /tmp/build.log 2>&1  # both to ONE file (order matters!)",
      "cmd 2>&1 | grep -i error  # merge to stdout then filter with grep",
      "cmd 2>> /var/log/myapp/errors.log  # APPEND stderr instead of overwrite"
