    memoryTip: "`-X` = method, `-H` = header, `-d` = data",
    outputExample: `$ curl -s -X POST -H 'Content-Type: application/json' -d '{"order_id":"ORD-9981"}' https://api.example.com/orders
{"status":"created","id":"ORD-9981"}`,
